import type { BehaviorTrackingProps } from '../../../../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../../../../core/types/data-props.js';
import type { MaskingProps } from '../../../../../core/types/masking-props.js';
import type { StylingProps } from '../../../../../core/types/styling-props.js';
import type { SeriesCurve, Timeseries, TimeseriesDatapoint } from '../../../types/timeseries.js';
/**
 * Sparkline variant
 * @public
 */
export type SparklineVariant = 'line' | 'area' | 'bar';
/**
 * Sparkline labels alignment
 * @public
 */
export type SparklinLabelsAlignment = 'left' | 'right';
/**
 * Sparkline gap policy
 * @public
 */
export type SparklineGapPolicy = 'connect' | 'gap';
/**
 * Sparkline datapoint
 * @internal
 */
export interface SparklineDatapointMetadata extends TimeseriesDatapoint {
    isGap?: boolean;
}
/**
 * Sparkline props
 * @public
 */
export interface SparklineProps extends StylingProps, MaskingProps, DataTestId, BehaviorTrackingProps {
    /** Data to show */
    data: Timeseries | Timeseries[];
    /** Sparkline color */
    color?: string;
    /** Sparkline variant (line, area) */
    variant?: SparklineVariant;
    /** Whether Sparkline shows X Axis ticks or not */
    showTicks?: boolean;
    /** When true: Sets an overlay with default loader */
    loading?: boolean;
    /** Gap policy */
    gapPolicy?: SparklineGapPolicy;
    /**
     * Curve shape of the series
     * @defaultValue 'linear'
     */
    curve?: SeriesCurve;
    /** Whether Sparkline shows min/max values or not */
    showContextValues?: boolean;
    /** Whether Sparkline aligns labels to left or right */
    /**
     * Curve shape of the series
     * @defaultValue 'left'
     */
    labelsAlignment?: SparklinLabelsAlignment;
    /** When Sparkline labels have a fixed width */
    labelsFixedWidth?: number;
    /**
     * Width of the sparkline component
     * Accepts string values (e.g., '100%', '200px') or numeric values (rendered as pixels)
     */
    width?: string | number;
    /**
     * Height of the sparkline component
     * Accepts string values (e.g., '50px', '100%') or numeric values (rendered as pixels)
     */
    height?: string | number;
}
